import { Component, OnInit, AfterViewInit } from '@angular/core';
import { UserService } from 'src/app/services/user/user.service';
import { Utilisateur } from 'src/app/models/utilisateur';
import { Router } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import * as bootstrap from 'bootstrap';

@Component({
  selector: 'app-profile',
  templateUrl: './profile.component.html',
  styleUrls: ['./profile.component.css']
})
export class ProfileComponent implements OnInit, AfterViewInit {
  user: Utilisateur | null = null;
  error: string | null = null;
  isEditing: boolean = false;
  profileForm: FormGroup;
  passwordForm: FormGroup;
  toasts: { title: string; message: string; type: string; action?: { label: string; callback: () => void } }[] = [];
  private passwordModal: bootstrap.Modal | undefined;
  selectedFile: File | null = null;
  timestamp: number = Date.now();

  constructor(
    private userService: UserService,
    private router: Router,
    private fb: FormBuilder
  ) {
    this.profileForm = this.fb.group({
      firstName: ['', [Validators.required, Validators.minLength(2), Validators.pattern(/^[a-zA-Z\s]*$/)]],
      lastName: ['', [Validators.required, Validators.minLength(2), Validators.pattern(/^[a-zA-Z\s]*$/)]],
      email: ['', [Validators.required, Validators.email]],
      dateNaissance: ['', [Validators.required, this.minimumAgeValidator(18)]]
    });

    this.passwordForm = this.fb.group({
      newPassword: ['', [Validators.required, Validators.minLength(6)]],
      confirmPassword: ['', Validators.required]
    }, { validators: this.passwordMatchValidator });
  }

  ngOnInit(): void {
    this.loadUserDetails();
  }

  ngAfterViewInit(): void {
    const modalElement = document.getElementById('changePasswordModal');
    if (modalElement) {
      this.passwordModal = new bootstrap.Modal(modalElement, {
        backdrop: true,
        keyboard: true
      });
      modalElement.addEventListener('hidden.bs.modal', () => {
        const backdrop = document.querySelector('.modal-backdrop');
        if (backdrop) {
          backdrop.remove();
        }
        const body = document.body;
        body.classList.remove('modal-open');
        body.style.overflow = '';
        body.style.paddingRight = '';
      });
    }
    this.initializeToasts();
  }

  loadUserDetails(): void {
    this.userService.getUserDetails().subscribe({
      next: (data) => {
        this.user = data || new Utilisateur();
        if (this.user) {
          this.profileForm.patchValue({
            firstName: this.user.firstName,
            lastName: this.user.lastName,
            email: this.user.email,
            dateNaissance: this.user.dateNaissance
          });
        }
        this.error = null;
        this.timestamp = Date.now();
      },
      error: (err) => {
        this.error = err.status === 401 ? 'Session expirée, veuillez vous reconnecter' : 'Erreur lors de la récupération des données';
        this.user = null;
      }
    });
  }

  editProfile(): void {
    this.isEditing = true;
  }

  saveProfile(): void {
    if (this.profileForm.valid && this.user) {
      const updatedUser = new Utilisateur({
        idUtilisateur: this.user.idUtilisateur,
        firstName: this.profileForm.value.firstName,
        lastName: this.profileForm.value.lastName,
        email: this.profileForm.value.email,
        dateNaissance: this.profileForm.value.dateNaissance,
        password: this.user.password,
        photo: this.user.photo,
        role: this.user.role,
        status: this.user.status,
        dateInscription: this.user.dateInscription
      });

      this.userService.updateUserDetails(updatedUser).subscribe({
        next: (data) => {
          this.user = data;
          this.isEditing = false;
          this.addToast('Succès', 'Profil mis à jour avec succès !', 'toast-success');
          this.timestamp = Date.now();
        },
        error: (err) => {
          this.addToast('Erreur', 'Échec de la mise à jour du profil. Veuillez réessayer.', 'toast-error');
        }
      });
    } else {
      Object.keys(this.profileForm.controls).forEach(field => {
        const control = this.profileForm.get(field);
        control?.markAsTouched();
        this.validateField(field);
      });
    }
  }

  cancelEdit(): void {
    this.isEditing = false;
    this.loadUserDetails();
  }

  changePhoto(): void {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (event) => {
      const file = (event.target as HTMLInputElement).files?.[0];
      if (file) {
        this.selectedFile = file;
        this.uploadPhoto();
      }
    };
    input.click();
  }

  uploadPhoto(): void {
    if (this.selectedFile) {
      this.userService.uploadPhoto(this.selectedFile).subscribe({
        next: (photoPath) => {
          if (this.user) {
            this.user.photo = photoPath;
            this.addToast('Succès', 'Photo de profil mise à jour avec succès !', 'toast-success');
            this.timestamp = Date.now();
            this.loadUserDetails();
          }
        },
        error: (err) => {
          this.addToast('Erreur', err.message || 'Échec du téléchargement de la photo. Veuillez réessayer.', 'toast-error');
        }
      });
    }
  }

  deleteAccount(): void {
    this.addToast(
      'Confirmation',
      'Êtes-vous sûr de vouloir supprimer votre compte ? Cette action est irréversible.',
      'toast-warning',
      {
        label: 'Oui',
        callback: () => {
          this.userService.deleteUser().subscribe({
            next: () => {
              localStorage.removeItem('token');
              this.addToast('Succès', 'Compte supprimé avec succès !', 'toast-success');
              this.router.navigate(['/login']);
            },
            error: (err) => {
              this.addToast('Erreur', 'Échec de la suppression du compte. Veuillez réessayer.', 'toast-error');
            }
          });
          this.removeToast(this.toasts.length - 1);
        }
      },
      {
        label: 'Non',
        callback: () => {
          this.removeToast(this.toasts.length - 1);
        }
      }
    );
  }

  openChangePasswordModal(): void {
    this.passwordForm.reset();
    this.passwordModal?.show();
  }

  changePasswordSubmit(): void {
    if (this.passwordForm.valid && this.user) {
      const newPassword = this.passwordForm.get('newPassword')?.value;
      const updatedUser = new Utilisateur({
        idUtilisateur: this.user.idUtilisateur,
        firstName: this.user.firstName,
        lastName: this.user.lastName,
        email: this.user.email,
        dateNaissance: this.user.dateNaissance,
        password: newPassword,
        photo: this.user.photo,
        role: this.user.role,
        status: this.user.status,
        dateInscription: this.user.dateInscription
      });

      this.userService.updateUserDetails(updatedUser).subscribe({
        next: (data) => {
          this.user = data;
          this.passwordModal?.hide();
          this.addToast('Succès', 'Mot de passe mis à jour avec succès !', 'toast-success');
          this.passwordForm.reset();
          setTimeout(() => {
            const backdrop = document.querySelector('.modal-backdrop');
            if (backdrop) {
              backdrop.remove();
            }
            const body = document.body;
            body.classList.remove('modal-open');
            body.style.overflow = '';
            body.style.paddingRight = '';
          }, 100);
        },
        error: (err) => {
          console.error('Erreur lors de la mise à jour du mot de passe:', err);
          this.addToast('Erreur', 'Échec de la mise à jour du mot de passe. Veuillez réessayer.', 'toast-error');
          this.passwordModal?.hide();
        }
      });
    } else {
      Object.keys(this.passwordForm.controls).forEach(field => {
        const control = this.passwordForm.get(field);
        control?.markAsTouched();
      });
    }
  }

  minimumAgeValidator(minAge: number) {
    return (control: any) => {
      if (!control.value) return null;
      const today = new Date();
      const birthDate = new Date(control.value);
      const age = today.getFullYear() - birthDate.getFullYear();
      const monthDiff = today.getMonth() - birthDate.getMonth();
      if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
        return age - 1 >= minAge ? null : { underage: true };
      }
      return age >= minAge ? null : { underage: true };
    };
  }

  validateField(field: string): void {
    const control = this.profileForm.get(field);
    if (control?.invalid && (control.touched || control.dirty)) {
      let message = '';
      let title = 'Erreur de validation';
      switch (field) {
        case 'firstName':
          if (control.errors?.['required']) message = 'Le prénom est requis.';
          else if (control.errors?.['minlength']) message = 'Le prénom doit contenir au moins 2 caractères.';
          else if (control.errors?.['pattern']) message = 'Le prénom ne doit contenir que des lettres.';
          break;
        case 'lastName':
          if (control.errors?.['required']) message = 'Le nom de famille est requis.';
          else if (control.errors?.['minlength']) message = 'Le nom de famille doit contenir au moins 2 caractères.';
          else if (control.errors?.['pattern']) message = 'Le nom de famille ne doit contenir que des lettres.';
          break;
        case 'email':
          if (control.errors?.['required']) message = 'L\'email est requis.';
          else if (control.errors?.['email']) message = 'Veuillez entrer un email valide.';
          break;
        case 'dateNaissance':
          if (control.errors?.['required']) message = 'La date de naissance est requise.';
          else if (control.errors?.['underage']) message = 'Vous devez avoir au moins 18 ans.';
          break;
      }
      if (message) {
        this.addToast(title, message, 'toast-error');
      }
    }
  }

  passwordMatchValidator(form: FormGroup) {
    const newPassword = form.get('newPassword')?.value;
    const confirmPassword = form.get('confirmPassword')?.value;
    return newPassword === confirmPassword ? null : { mismatch: true };
  }

  addToast(title: string, message: string, type: string, ...actions: { label: string; callback: () => void }[]): void {
    this.toasts.push({ title, message, type, action: actions.length > 0 ? actions[0] : undefined });
    setTimeout(() => {
      const toastElement = document.querySelectorAll('.toast')[this.toasts.length - 1];
      if (toastElement) {
        const toast = new bootstrap.Toast(toastElement, { delay: 10000 });
        toast.show();
      }
    }, 0);
    setTimeout(() => {
      this.toasts.shift();
    }, 10000);
  }

  removeToast(index: number): void {
    this.toasts.splice(index, 1);
  }

  initializeToasts(): void {
    document.querySelectorAll('.toast').forEach(toastElement => {
      const toast = new bootstrap.Toast(toastElement, { delay: 5000 });
      toast.show();
    });
  }
}
<app-navbar></app-navbar>

<div class="container mt-5">
  <div *ngIf="error" class="alert alert-danger alert-dismissible fade show" role="alert">
    {{ error }}
    <button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>
  </div>

  <div *ngIf="user" class="card shadow-sm p-4 animate__animated animate__fadeIn">
    <div class="row g-0">
      <div class="col-md-4 text-center">
        <img [src]="user.photo ? (user.photo + '?t=' + timestamp) : '/assets/img/team/icondefaut.webp'" alt="Photo de profil" class="profile-photo">
      </div>
      <div class="col-md-8">
        <h2 class="mb-4 text-black">{{ user.firstName }} {{ user.lastName }}</h2>
        <form [formGroup]="profileForm" (ngSubmit)="saveProfile()" *ngIf="isEditing">
          <div class="row row-cols-2 g-3" [ngClass]="{'edit-mode': isEditing}">
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">FirstName</h6>
                  <input type="text" class="form-control" formControlName="firstName" [ngClass]="{'is-invalid': profileForm.get('firstName')?.invalid && (profileForm.get('firstName')?.touched || profileForm.get('firstName')?.dirty)}">
                  <div *ngIf="profileForm.get('firstName')?.invalid && (profileForm.get('firstName')?.touched || profileForm.get('firstName')?.dirty)" class="invalid-feedback">
                    <div *ngIf="profileForm.get('firstName')?.errors?.['required']">Le prénom est requis.</div>
                    <div *ngIf="profileForm.get('firstName')?.errors?.['minlength']">Le prénom doit contenir au moins 2 caractères.</div>
                    <div *ngIf="profileForm.get('firstName')?.errors?.['pattern']">Le prénom ne doit contenir que des lettres.</div>
                  </div>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">LastName</h6>
                  <input type="text" class="form-control" formControlName="lastName" [ngClass]="{'is-invalid': profileForm.get('lastName')?.invalid && (profileForm.get('lastName')?.touched || profileForm.get('lastName')?.dirty)}">
                  <div *ngIf="profileForm.get('lastName')?.invalid && (profileForm.get('lastName')?.touched || profileForm.get('lastName')?.dirty)" class="invalid-feedback">
                    <div *ngIf="profileForm.get('lastName')?.errors?.['required']">Le nom de famille est requis.</div>
                    <div *ngIf="profileForm.get('lastName')?.errors?.['minlength']">Le nom de famille doit contenir au moins 2 caractères.</div>
                    <div *ngIf="profileForm.get('lastName')?.errors?.['pattern']">Le nom de famille ne doit contenir que des lettres.</div>
                  </div>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Email</h6>
                  <input type="email" class="form-control" formControlName="email" [ngClass]="{'is-invalid': profileForm.get('email')?.invalid && (profileForm.get('email')?.touched || profileForm.get('email')?.dirty)}">
                  <div *ngIf="profileForm.get('email')?.invalid && (profileForm.get('email')?.touched || profileForm.get('email')?.dirty)" class="invalid-feedback">
                    <div *ngIf="profileForm.get('email')?.errors?.['required']">L'email est requis.</div>
                    <div *ngIf="profileForm.get('email')?.errors?.['email']">Veuillez entrer un email valide.</div>
                  </div>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Date of Birth</h6>
                  <input type="date" class="form-control" formControlName="dateNaissance" [ngClass]="{'is-invalid': profileForm.get('dateNaissance')?.invalid && (profileForm.get('dateNaissance')?.touched || profileForm.get('dateNaissance')?.dirty)}">
                  <div *ngIf="profileForm.get('dateNaissance')?.invalid && (profileForm.get('dateNaissance')?.touched || profileForm.get('dateNaissance')?.dirty)" class="invalid-feedback">
                    <div *ngIf="profileForm.get('dateNaissance')?.errors?.['required']">La date de naissance est requise.</div>
                    <div *ngIf="profileForm.get('dateNaissance')?.errors?.['underage']">Vous devez avoir au moins 18 ans.</div>
                  </div>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Date d'inscription</h6>
                  <p class="card-text">{{ user.dateInscription }}</p>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Role</h6>
                  <p class="card-text">{{ user.role }}</p>
                </div>
              </div>
            </div>
            <div class="col">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Status</h6>
                  <p class="card-text">{{ user.status }}</p>
                </div>
              </div>
            </div>
            <div class="col-12">
              <div class="card h-100 bg-light border-0">
                <div class="card-body">
                  <h6 class="card-title text-muted">Receive Email Notifications</h6>
                  <div>
                    <button class="btn btn-success btn-sm me-2">Yes</button>
                    <button class="btn btn-outline-secondary btn-sm">No</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </form>
        <div class="row row-cols-2 g-3" *ngIf="!isEditing">
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">FirstName</h6>
                <p class="card-text">{{ user.firstName }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">LastName</h6>
                <p class="card-text">{{ user.lastName }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">Email</h6>
                <p class="card-text">{{ user.email }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">Date of Birth</h6>
                <p class="card-text">{{ user.dateNaissance }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">Date d'inscription</h6>
                <p class="card-text">{{ user.dateInscription }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">Role</h6>
                <p class="card-text">{{ user.role }}</p>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card h-100 bg-light border-0">
              <div class="card-body">
                <h6 class="card-title text-muted">Status</h6>
                <p class="card-text">{{ user.status }}</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    <div class="mt-4 text-center">
      <button *ngIf="!isEditing" class="btn btn-success me-2" (click)="editProfile()"><i class="fas fa-edit"></i> Edit</button>
      <button *ngIf="isEditing" class="btn btn-success me-2" (click)="saveProfile()">Save</button>
      <button *ngIf="isEditing" class="btn btn-secondary me-2" (click)="cancelEdit()">Cancel</button>
      <button class="btn btn-primary me-2" (click)="openChangePasswordModal()" data-bs-toggle="modal" data-bs-target="#changePasswordModal"><i class="fas fa-lock"></i> Change Password</button>
      <button class="btn btn-warning me-2" (click)="changePhoto()"><i class="fas fa-camera"></i> Change Photo</button>
      <button class="btn btn-danger" (click)="deleteAccount()"><i class="fas fa-trash"></i> Delete Account</button>
    </div>
  </div>
</div>

<div class="toast-container position-fixed top-0 end-0 p-3">
  <div *ngFor="let toast of toasts; let i = index" class="toast align-items-center text-white" [ngClass]="toast.type" role="alert" aria-live="assertive" aria-atomic="true">
    <div class="d-flex">
      <div class="toast-body">
        <strong>{{ toast.title }}</strong>
        <p class="mb-0">{{ toast.message }}</p>
        <div *ngIf="toast.action" class="mt-2">
          <button type="button" class="btn btn-sm btn-primary me-2" (click)="toast.action.callback(); $event.stopPropagation()">{{ toast.action.label }}</button>
        </div>
      </div>
      <button type="button" class="btn-close btn-close-white me-2 m-auto" (click)="removeToast(i)" data-bs-dismiss="toast" aria-label="Close"></button>
    </div>
  </div>
</div>

<div class="modal fade" id="changePasswordModal" tabindex="-1" aria-labelledby="changePasswordModalLabel" aria-hidden="true">
  <div class="modal-dialog">
    <div class="modal-content">
      <div class="modal-header">
        <h5 class="modal-title" id="changePasswordModalLabel">Changer le mot de passe</h5>
        <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>
      </div>
      <div class="modal-body">
        <form [formGroup]="passwordForm" (ngSubmit)="changePasswordSubmit()">
          <div class="mb-3">
            <label for="newPassword" class="form-label">Nouveau mot de passe</label>
            <input type="password" class="form-control" id="newPassword" formControlName="newPassword" [ngClass]="{'is-invalid': passwordForm.get('newPassword')?.invalid && (passwordForm.get('newPassword')?.touched || passwordForm.get('newPassword')?.dirty)}">
            <div *ngIf="passwordForm.get('newPassword')?.invalid && (passwordForm.get('newPassword')?.touched || passwordForm.get('newPassword')?.dirty)" class="invalid-feedback">
              <div *ngIf="passwordForm.get('newPassword')?.errors?.['required']">Le mot de passe est requis.</div>
              <div *ngIf="passwordForm.get('newPassword')?.errors?.['minlength']">Le mot de passe doit contenir au moins 6 caractères.</div>
            </div>
          </div>
          <div class="mb-3">
            <label for="confirmPassword" class="form-label">Confirmer le mot de passe</label>
            <input type="password" class="form-control" id="confirmPassword" formControlName="confirmPassword" [ngClass]="{'is-invalid': passwordForm.get('confirmPassword')?.invalid && (passwordForm.get('confirmPassword')?.touched || passwordForm.get('confirmPassword')?.dirty)}">
            <div *ngIf="passwordForm.get('confirmPassword')?.invalid && (passwordForm.get('confirmPassword')?.touched || passwordForm.get('confirmPassword')?.dirty)" class="invalid-feedback">
              <div *ngIf="passwordForm.get('confirmPassword')?.errors?.['required']">La confirmation est requise.</div>
              <div *ngIf="passwordForm.errors?.['mismatch']">Les mots de passe ne correspondent pas.</div>
            </div>
          </div>
          <button type="submit" class="btn btn-primary" [disabled]="passwordForm.invalid">Enregistrer</button>
          <button type="button" class="btn btn-secondary ms-2" data-bs-dismiss="modal">Annuler</button>
        </form>
      </div>
    </div>
  </div>
</div>

<app-footer></app-footer>
